args.sparql:
SELECT ?year ?winnerLabel WHERE {
  ?marathon wdt:P276 wd:Q60 ;
            wdt:P1346 ?winner ;
            wdt:P585 ?date .
  ?winner wdt:P27 wd:Q30 .
  ?winner rdfs:label ?winnerLabel .
  FILTER(LANG(?winnerLabel) = "en").
  BIND(YEAR(?date) AS ?year)
}
ORDER BY DESC(?year)
LIMIT 5

SELECT ?year ?americanLabel WHERE {
  ?american wdt:P27 wd:Q30;
            p:P2522 ?win.
  ?win ps:P2522 wd:Q752138;
       pq:P585 ?date.
  ?american rdfs:label ?americanLabel.
  FILTER(LANG(?americanLabel) = "en").
  BIND(YEAR(?date) AS ?year)
}
ORDER BY DESC(?year)
LIMIT 1
